1	// B14.8b: 2-node federation Playwright e2e suite + ts-net guard.
2	//
3	// Each test spins up its own pair of ddx-server processes (1 hub + 1 spoke)
4	// on loopback, both with --tsnet=false so no Tailscale dependency leaks
5	// in. Both nodes register as spokes against the hub (the hub uses the
6	// hub_spoke role) so the hub's /federation page lists both, and any
7	// ?scope=federation fan-out returns rows from both nodes.
8	//
9	// The "ts-net guard" tests use a separate hub bound to 0.0.0.0 with a
10	// non-loopback host IP discovered at runtime; the registration request is
11	// issued against that non-loopback IP so the hub's requireFederationTrusted
12	// gate sees a non-loopback RemoteAddr. If no non-loopback IPv4 is available
13	// (CI image without an external interface), the ts-net guard tests
14	// test.skip with a clear message — the loopback flows still cover the
15	// other AC items.
16	
17	import { expect, request as playwrightRequest, test } from '@playwright/test';
18	import type { APIRequestContext } from '@playwright/test';
19	import { spawn, type ChildProcessWithoutNullStreams } from 'node:child_process';
20	import * as fs from 'node:fs';
21	import * as net from 'node:net';
22	import * as os from 'node:os';
23	import * as path from 'node:path';
24	import { fileURLToPath } from 'node:url';
25	import { ensureDdxE2EBinary } from './ddx-binary';
26	
27	const FRONTEND_DIR = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
28	const FIXTURE_DIR = path.resolve(FRONTEND_DIR, 'e2e/fixtures');
29	
30	async function freePort(): Promise<number> {
31		return new Promise((resolve, reject) => {
32			const srv = net.createServer();
33			srv.once('error', reject);
34			srv.listen(0, '127.0.0.1', () => {
35				const a = srv.address();
36				if (!a || typeof a === 'string') {
37					srv.close(() => reject(new Error('alloc port')));
38					return;
39				}
40				const port = a.port;
41				srv.close(() => resolve(port));
42			});
43		});
44	}
45	
46	function copyFixture(): string {
47		const root = fs.mkdtempSync(path.join(os.tmpdir(), 'ddx-fed-e2e-ws-'));
48		const ent = (rel: string) => path.join(FIXTURE_DIR, rel);
49		const dst = (rel: string) => path.join(root, rel);
50		function walk(srcRel: string) {
51			const stat = fs.statSync(ent(srcRel));
52			if (stat.isDirectory()) {
53				fs.mkdirSync(dst(srcRel), { recursive: true });
54				for (const child of fs.readdirSync(ent(srcRel))) {
55					walk(path.join(srcRel, child));
56				}
57			} else {
58				fs.mkdirSync(path.dirname(dst(srcRel)), { recursive: true });
59				fs.copyFileSync(ent(srcRel), dst(srcRel));
60			}
61		}
62		for (const top of fs.readdirSync(FIXTURE_DIR)) {
63			walk(top);
64		}
65		return root;
66	}
