68	interface SpawnedServer {
69		port: number;
70		addr: string;
71		baseURL: string;
72		root: string;
73		child: ChildProcessWithoutNullStreams;
74		stdoutBuf: string;
75		stderrBuf: string;
76		api: APIRequestContext;
77	}
78	
79	async function waitHealthy(api: APIRequestContext, child: ChildProcessWithoutNullStreams) {
80		let last: unknown;
81		for (let i = 0; i < 80; i++) {
82			if (child.exitCode !== null) {
83				throw new Error(`server exited early (${child.exitCode})`);
84			}
85			try {
86				const r = await api.get('/api/health', { timeout: 500 });
87				if (r.ok()) return;
88			} catch (e) {
89				last = e;
90			}
91			await new Promise((r) => setTimeout(r, 125));
92		}
93		throw new Error(`server not healthy: ${String(last)}`);
94	}
95	
96	interface SpawnOpts {
97		hubMode?: boolean;
98		hubURL?: string;
99		allowPlainHTTP?: boolean;
100		bindAddr?: string;
101		selfURL?: string;
102		nodeName?: string;
103		// When set, reuse this directory rather than copying the fixture again.
104		// Required when restarting a spoke so the persisted identity_fingerprint
105		// survives — otherwise the hub rejects the restart as a 409 duplicate
106		// node_id.
107		reuseRoot?: string;
108	}
109	
110	async function spawnServer(opts: SpawnOpts): Promise<SpawnedServer> {
111		const bin = ensureDdxE2EBinary();
112		const port = await freePort();
113		const bindAddr = opts.bindAddr ?? '127.0.0.1';
114		const root = opts.reuseRoot ?? copyFixture();
115		const args = ['server', '--port', String(port), '--addr', bindAddr, '--tsnet=false'];
116		if (opts.hubMode) args.push('--hub-mode');
117		if (opts.allowPlainHTTP) args.push('--federation-allow-plain-http');
118		if (opts.hubURL) args.push('--hub-address', opts.hubURL);
119		if (opts.selfURL) args.push('--federation-self-url', opts.selfURL);
120		const child = spawn(bin, args, {
121			cwd: root,
122			env: {
123				...process.env,
124				DDX_NODE_NAME: opts.nodeName ?? `fed-e2e-${port}`,
125				XDG_DATA_HOME: path.join(root, '.xdg-data'),
126				XDG_CONFIG_HOME: path.join(root, '.xdg-config')
127			}
128		});
129		const s: SpawnedServer = {
130			port,
131			addr: bindAddr,
132			baseURL: `https://127.0.0.1:${port}`,
133			root,
134			child,
135			stdoutBuf: '',
136			stderrBuf: '',
137			api: await playwrightRequest.newContext({
138				baseURL: `https://127.0.0.1:${port}`,
139				ignoreHTTPSErrors: true
140			})
141		};
142		child.stdout.on('data', (d) => {
143			s.stdoutBuf += d.toString();
144		});
145		child.stderr.on('data', (d) => {
146			s.stderrBuf += d.toString();
147		});
148		await waitHealthy(s.api, child);
149		return s;
150	}
151	
152	async function stopServer(s: SpawnedServer, opts: { keepRoot?: boolean } = {}) {
153		await s.api.dispose().catch(() => {});
154		if (s.child.exitCode === null) {
155			s.child.kill();
156			await Promise.race([
157				new Promise((r) => s.child.once('exit', r)),
158				new Promise((r) =>
159					setTimeout(() => {
160						if (s.child.exitCode === null) s.child.kill('SIGKILL');
161						r(undefined);
162					}, 2500)
163				)
164			]);
165		}
166		if (!opts.keepRoot) fs.rmSync(s.root, { recursive: true, force: true });
167	}
168	
169	async function nodeIdOf(s: SpawnedServer): Promise<string> {
170		const r = await s.api.post('/graphql', {
171			data: { query: '{ nodeInfo { id } }' }
172		});
173		const body = (await r.json()) as { data: { nodeInfo: { id: string } } };
174		return body.data.nodeInfo.id;
175	}
176	
177	async function federationNodes(
178		s: SpawnedServer
179	): Promise<Array<{ nodeId: string; status: string; name: string }>> {
180		const r = await s.api.post('/graphql', {
181			data: {
182				query: '{ federationNodes { nodeId status name } }'
183			}
184		});
185		const body = (await r.json()) as {
186			data: { federationNodes: Array<{ nodeId: string; status: string; name: string }> };
187		};
188		return body.data.federationNodes;
189	}
190	
191	async function triggerFanOut(s: SpawnedServer): Promise<void> {
192		// federatedBeads runs the fan-out path; the result is irrelevant — we
193		// only need the side effect of StatusUpdates landing in the registry.
194		await s.api.post('/graphql', {
195			data: { query: '{ federatedBeads { nodeId } }' }
196		});
197	}
