199	function firstNonLoopbackIPv4(): string | null {
200		const ifaces = os.networkInterfaces();
201		for (const list of Object.values(ifaces)) {
202			if (!list) continue;
203			for (const a of list) {
204				if (a.family === 'IPv4' && !a.internal) {
205					// Skip docker bridges / link-local — pick the first usable.
206					if (a.address.startsWith('169.254.')) continue;
207					return a.address;
208				}
209			}
210		}
211		return null;
212	}
