216	test.describe('federation 2-node e2e', () => {
217		test.setTimeout(150_000);
218	
219		test('hub /federation lists both nodes; scope=federation merges data; offline+restart cycle', async ({
220			page
221		}) => {
222			const hub = await spawnServer({ hubMode: true, nodeName: 'fed-e2e-hub' });
223			// Hub registers itself as a spoke (hub_spoke) so /federation lists it.
224			await registerHubSelfAsSpoke(hub);
225	
226			const spoke = await spawnServer({
227				hubURL: hub.baseURL,
228				selfURL: '', // default
229				nodeName: 'fed-e2e-spoke'
230			});
231	
232			try {
233				// Wait for both registrations to land in the hub registry.
234				await expect
235					.poll(async () => (await federationNodes(hub)).length, { timeout: 10_000 })
236					.toBe(2);
237	
238				const fedNodes = await federationNodes(hub);
239				const ids = new Set(fedNodes.map((n) => n.nodeId));
240				expect(ids.has(await nodeIdOf(hub))).toBe(true);
241				expect(ids.has(await nodeIdOf(spoke))).toBe(true);
242				for (const n of fedNodes) {
243					expect(['active', 'registered']).toContain(n.status);
244				}
245	
246				// /federation page renders both nodes.
247				await page.goto(`${hub.baseURL}/federation`);
248				await expect(page.getByTestId('federation-page')).toBeVisible();
249				const rows = page.getByTestId('federation-row');
250				await expect(rows).toHaveCount(2);
251	
252				// Status badges reflect status (active OR registered before the
253				// first heartbeat lands; both are healthy states).
254				const badges = page.getByTestId('federation-status-badge');
255				await expect(badges).toHaveCount(2);
256				for (let i = 0; i < 2; i++) {
257					const txt = (await badges.nth(i).textContent())?.trim().toLowerCase();
258					expect(['active', 'registered']).toContain(txt);
259				}
260	
261				// scope=federation fan-out combined view shows beads from BOTH
262				// nodes. Each fixture workspace seeds 3 beads (fx-001/2/3); with
263				// 2 federated nodes we expect 6 rows.
264				const hubNodeId = await nodeIdOf(hub);
265				await page.goto(`${hub.baseURL}/nodes/${hubNodeId}/beads?scope=federation`);
266				await expect(page.getByTestId('scope-indicator')).toBeVisible();
267				await expect(page.getByTestId('scope-toggle')).toContainText('federation');
268				// Both fixture beads exist; expect at least one row per node by
269				// their fixture title prefix.
270				await expect
271					.poll(async () => await page.getByText('Open ready bead').count(), { timeout: 10_000 })
272					.toBeGreaterThanOrEqual(2);
273	
274				// Toggle switches LOCAL vs FEDERATION.
275				await page.getByTestId('scope-toggle').click();
276				await expect(page).not.toHaveURL(/scope=federation/);
277				await expect(page.getByTestId('scope-indicator')).toHaveCount(0);
278				// Local view still has 3 beads (fx-001/2/3).
279				await expect(page.getByText('Open ready bead')).toBeVisible();
280	
281				// Stop the spoke process. Keep its root so the persisted
282				// identity_fingerprint survives the restart cycle (re-registration
283				// with a different fingerprint would trip the hub's 409 duplicate-
284				// node_id guard).
285				const spokeRoot = spoke.root;
286				await stopServer(spoke, { keepRoot: true });
287				// Close the hubAsSpoke too if it points at the spoke — it does
288				// not, the hub registers itself; keep it running.
289	
290				await expect
291					.poll(
292						async () => {
293							await triggerFanOut(hub);
294							const ns = await federationNodes(hub);
295							const found = ns.find((n) => n.name === 'fed-e2e-spoke');
296							return found?.status ?? 'missing';
297						},
298						{ timeout: 15_000, intervals: [500, 1000, 1500] }
299					)
300					.toBe('offline');
301	
302				// /federation page reflects the offline badge for the spoke.
303				await page.goto(`${hub.baseURL}/federation`);
304				const offlineRow = page.locator('[data-testid="federation-row"][data-status="offline"]');
305				await expect(offlineRow).toHaveCount(1);
306				await expect(offlineRow.locator('[data-testid="federation-status-badge"]')).toContainText(
307					/offline/i
308				);
309	
310				// Restart the spoke — registration alone (handshake → StatusActive)
311				// returns it to active without waiting on a heartbeat tick.
312				const spoke2 = await spawnServer({
313					hubURL: hub.baseURL,
314					nodeName: 'fed-e2e-spoke',
315					reuseRoot: spokeRoot
316				});
317				try {
318					await expect
319						.poll(
320							async () => {
321								const ns = await federationNodes(hub);
322								const found = ns.find((n) => n.name === 'fed-e2e-spoke');
323								return found?.status ?? 'missing';
324							},
325							{ timeout: 15_000, intervals: [500, 1000] }
326						)
327						.toMatch(/active|registered/);
328	
329					await page.goto(`${hub.baseURL}/federation`);
330					const activeRows = page.locator(
331						'[data-testid="federation-row"][data-status="active"], [data-testid="federation-row"][data-status="registered"]'
332					);
333					await expect(activeRows).toHaveCount(2);
334				} finally {
335					await stopServer(spoke2);
336				}
337			} finally {
338				await stopServer(hub);
339			}
340		});
341	});
