343	// Drive the hub to register itself as a spoke (hub_spoke role) via a direct
344	// loopback POST to /api/federation/register. This avoids spinning up a third
345	// process just to obtain a 2-row /federation listing.
346	async function registerHubSelfAsSpoke(hub: SpawnedServer): Promise<void> {
347		const hubNodeId = await nodeIdOf(hub);
348		const resp = await hub.api.post('/api/federation/register', {
349			data: {
350				node_id: hubNodeId,
351				identity_fingerprint: 'hub-self-fp',
352				name: 'fed-e2e-hub',
353				url: hub.baseURL,
354				ddx_version: '0.1.0',
355				schema_version: '1',
356				capabilities: ['beads', 'runs']
357			}
358		});
359		if (!resp.ok()) throw new Error(`hub self-register failed: ${resp.status()}`);
360	}
