364	test.describe('federation ts-net guard', () => {
365		test.setTimeout(60_000);
366	
367		test('plain-HTTP non-loopback registration is rejected without --federation-allow-plain-http', async () => {
368			const externalIP = firstNonLoopbackIPv4();
369			test.skip(!externalIP, 'no non-loopback IPv4 interface available');
370	
371			const hub = await spawnServer({
372				hubMode: true,
373				bindAddr: '0.0.0.0',
374				nodeName: 'tsnet-guard-strict'
375			});
376			try {
377				const externalAPI = await playwrightRequest.newContext({
378					baseURL: `https://${externalIP}:${hub.port}`,
379					ignoreHTTPSErrors: true
380				});
381				try {
382					const resp = await externalAPI.post('/api/federation/register', {
383						data: {
384							node_id: 'attacker-node',
385							identity_fingerprint: 'fp',
386							name: 'attacker',
387							url: 'https://attacker.example:7743',
388							ddx_version: '0.1.0',
389							schema_version: '1',
390							capabilities: ['beads']
391						}
392					});
393					expect(resp.status()).toBe(403);
394					const body = (await resp.json()) as { error?: string };
395					expect(body.error ?? '').toMatch(/federation-allow-plain-http|trusted|loopback|forbidden/i);
396				} finally {
397					await externalAPI.dispose();
398				}
399	
400				// Sanity: registry must NOT have recorded the attacker node.
401				const fedNodes = await federationNodes(hub);
402				expect(fedNodes.find((n) => n.nodeId === 'attacker-node')).toBeUndefined();
403			} finally {
404				await stopServer(hub);
405			}
406		});
407	
408		test('plain-HTTP non-loopback registration is accepted with --federation-allow-plain-http and emits WARN', async () => {
409			const externalIP = firstNonLoopbackIPv4();
410			test.skip(!externalIP, 'no non-loopback IPv4 interface available');
411	
412			const hub = await spawnServer({
413				hubMode: true,
414				allowPlainHTTP: true,
415				bindAddr: '0.0.0.0',
416				nodeName: 'tsnet-guard-permissive'
417			});
418			try {
419				const externalAPI = await playwrightRequest.newContext({
420					baseURL: `https://${externalIP}:${hub.port}`,
421					ignoreHTTPSErrors: true
422				});
423				try {
424					const resp = await externalAPI.post('/api/federation/register', {
425						data: {
426							node_id: 'opt-out-node',
427							identity_fingerprint: 'fp',
428							name: 'opt-out',
429							url: 'https://opt-out.example:7743',
430							ddx_version: '0.1.0',
431							schema_version: '1',
432							capabilities: ['beads']
433						}
434					});
435					expect(resp.status()).toBe(200);
436				} finally {
437					await externalAPI.dispose();
438				}
439	
440				// Registry now contains the registered node.
441				await expect
442					.poll(
443						async () => (await federationNodes(hub)).find((n) => n.nodeId === 'opt-out-node')?.nodeId,
444						{ timeout: 5_000 }
445					)
446					.toBe('opt-out-node');
447	
448				// WARN log captured: federation_hub.go writes
449				//   "WARN: federation: accepted plain-HTTP registration node_id=..."
450				// to stderr via log.Printf.
451				expect(hub.stderrBuf).toMatch(/accepted plain-HTTP registration/i);
452				expect(hub.stderrBuf).toMatch(/opt-out-node/);
453			} finally {
454				await stopServer(hub);
455			}
456		});
457	});
